def simulate_golden_swallow_foraging(foraging_height):
    # Golden swallows typically forage under 20m, rarely over 30m
    if foraging_height < 0:
        return "Invalid height: must be non-negative"
    if foraging_height <= 20:
        return "Foraging at typical height (<=20m)"
    elif foraging_height <= 30:
        return "Foraging at rare height (20-30m)"
    else:
        return "Foraging height exceeds typical range (>30m)"

# Example usage:
print(simulate_golden_swallow_foraging(15))  # Output: Foraging at typical height (<=20m)
print(simulate_golden_swallow_foraging(25))  # Output: Foraging at rare height (20-30m)
